 1→import type Database from 'better-sqlite3';
 2→
 3→export interface PushSubscriptionRow {
 4→	id: string;
 5→	endpoint: string;
 6→	p256dh: string;
 7→	auth: string;
 8→	created_at: string;
 9→}
10→
11→export function createPushSubscription(
12→	db: Database.Database,
13→	input: { id: string; endpoint: string; p256dh: string; auth: string }
14→): PushSubscriptionRow {
15→	db.prepare(
16→		`INSERT INTO push_subscriptions (id, endpoint, p256dh, auth)
17→		 VALUES (?, ?, ?, ?)`
18→	).run(input.id, input.endpoint, input.p256dh, input.auth);
19→
20→	return getPushSubscriptionById(db, input.id)!;
21→}
22→
23→function getPushSubscriptionById(db: Database.Database, id: string): PushSubscriptionRow | null {
24→	return (
25→		(db.prepare('SELECT * FROM push_subscriptions WHERE id = ?').get(id) as
26→			| PushSubscriptionRow
27→			| undefined) ?? null
28→	);
29→}
30→
31→export function getPushSubscriptionByEndpoint(
32→	db: Database.Database,
33→	endpoint: string
34→): PushSubscriptionRow | null {
35→	return (
36→		(db.prepare('SELECT * FROM push_subscriptions WHERE endpoint = ?').get(endpoint) as
37→			| PushSubscriptionRow
38→			| undefined) ?? null
39→	);
40→}
41→
42→export function getAllPushSubscriptions(db: Database.Database): PushSubscriptionRow[] {
43→	return db
44→		.prepare('SELECT * FROM push_subscriptions ORDER BY created_at')
45→		.all() as PushSubscriptionRow[];
46→}
47→
48→export function deletePushSubscription(db: Database.Database, endpoint: string): void {
49→	db.prepare('DELETE FROM push_subscriptions WHERE endpoint = ?').run(endpoint);
50→}
