 1→export interface PushSubscriptionData {
 2→	endpoint: string;
 3→	keys: {
 4→		p256dh: string;
 5→		auth: string;
 6→	};
 7→}
 8→
 9→export interface PushNotificationPayload {
10→	title: string;
11→	body: string;
12→	url?: string;
13→	tag?: string;
14→}
15→
16→export interface PushService {
17→	subscribe(subscription: PushSubscriptionData): Promise<void>;
18→	unsubscribe(endpoint: string): Promise<void>;
19→	sendNotification(
20→		subscription: PushSubscriptionData,
21→		payload: PushNotificationPayload
22→	): Promise<void>;
23→	broadcast(payload: PushNotificationPayload): Promise<void>;
24→}
