 1→import type { PushService, PushSubscriptionData, PushNotificationPayload } from './push-service.js';
 2→
 3→interface SentNotification {
 4→	subscription: PushSubscriptionData;
 5→	payload: PushNotificationPayload;
 6→}
 7→
 8→export class FakePushService implements PushService {
 9→	readonly subscriptions: PushSubscriptionData[] = [];
10→	readonly sent: SentNotification[] = [];
11→
12→	async subscribe(subscription: PushSubscriptionData): Promise<void> {
13→		const exists = this.subscriptions.some((s) => s.endpoint === subscription.endpoint);
14→		if (!exists) {
15→			this.subscriptions.push(subscription);
16→		}
17→	}
18→
19→	async unsubscribe(endpoint: string): Promise<void> {
20→		const idx = this.subscriptions.findIndex((s) => s.endpoint === endpoint);
21→		if (idx !== -1) {
22→			this.subscriptions.splice(idx, 1);
23→		}
24→	}
25→
26→	async sendNotification(
27→		subscription: PushSubscriptionData,
28→		payload: PushNotificationPayload
29→	): Promise<void> {
30→		this.sent.push({ subscription, payload });
31→	}
32→
33→	async broadcast(payload: PushNotificationPayload): Promise<void> {
34→		for (const sub of this.subscriptions) {
35→			await this.sendNotification(sub, payload);
36→		}
37→	}
38→}
