 1→import webpush from 'web-push';
 2→import type Database from 'better-sqlite3';
 3→import type { PushService, PushSubscriptionData, PushNotificationPayload } from './push-service.js';
 4→import {
 5→	createPushSubscription,
 6→	getPushSubscriptionByEndpoint,
 7→	getAllPushSubscriptions,
 8→	deletePushSubscription
 9→} from '../db/push-subscriptions.js';
10→import { generateId } from '../api-utils.js';
11→
12→export interface VapidConfig {
13→	publicKey: string;
14→	privateKey: string;
15→	email: string;
16→}
17→
18→export class WebPushService implements PushService {
19→	constructor(
20→		private db: Database.Database,
21→		private vapid: VapidConfig
22→	) {
23→		webpush.setVapidDetails(`mailto:${vapid.email}`, vapid.publicKey, vapid.privateKey);
24→	}
25→
26→	async subscribe(subscription: PushSubscriptionData): Promise<void> {
27→		const existing = getPushSubscriptionByEndpoint(this.db, subscription.endpoint);
28→		if (!existing) {
29→			createPushSubscription(this.db, {
30→				id: generateId(),
31→				endpoint: subscription.endpoint,
32→				p256dh: subscription.keys.p256dh,
33→				auth: subscription.keys.auth
34→			});
35→		}
36→	}
37→
38→	async unsubscribe(endpoint: string): Promise<void> {
39→		deletePushSubscription(this.db, endpoint);
40→	}
41→
42→	async sendNotification(
43→		subscription: PushSubscriptionData,
44→		payload: PushNotificationPayload
45→	): Promise<void> {
46→		try {
47→			await webpush.sendNotification(
48→				{
49→					endpoint: subscription.endpoint,
50→					keys: subscription.keys
51→				},
52→				JSON.stringify(payload)
53→			);
54→		} catch (err) {
55→			// If subscription is expired/invalid, clean it up
56→			const code = (err as { statusCode?: number }).statusCode;
57→			if (code === 410 || code === 404) {
58→				deletePushSubscription(this.db, subscription.endpoint);
59→			}
60→		}
61→	}
62→
63→	async broadcast(payload: PushNotificationPayload): Promise<void> {
64→		const rows = getAllPushSubscriptions(this.db);
65→		await Promise.all(
66→			rows.map((row) =>
67→				this.sendNotification(
68→					{ endpoint: row.endpoint, keys: { p256dh: row.p256dh, auth: row.auth } },
69→					payload
70→				)
71→			)
72→		);
73→	}
74→}
75→
76→export function generateVapidKeys(): { publicKey: string; privateKey: string } {
77→	return webpush.generateVAPIDKeys();
78→}
