 1→import type Database from 'better-sqlite3';
 2→import type { PushService, PushSubscriptionData } from './push-service.js';
 3→import { jsonResponse, errorResponse } from '../api-utils.js';
 4→import {
 5→	deletePushSubscription,
 6→	getPushSubscriptionByEndpoint,
 7→	createPushSubscription
 8→} from '../db/push-subscriptions.js';
 9→import { generateId } from '../api-utils.js';
10→
11→interface SubscribeBody {
12→	endpoint?: unknown;
13→	keys?: unknown;
14→}
15→
16→export class PushController {
17→	constructor(
18→		private db: Database.Database,
19→		private pushService: PushService
20→	) {}
21→
22→	async handleSubscribe(body: unknown): Promise<Response> {
23→		const b = body as SubscribeBody;
24→
25→		if (!b.endpoint || typeof b.endpoint !== 'string') {
26→			return errorResponse('endpoint is required', 400);
27→		}
28→
29→		const keys = b.keys as { p256dh?: unknown; auth?: unknown } | undefined;
30→		if (!keys || typeof keys.p256dh !== 'string' || typeof keys.auth !== 'string') {
31→			return errorResponse('keys.p256dh and keys.auth are required', 400);
32→		}
33→
34→		const sub: PushSubscriptionData = {
35→			endpoint: b.endpoint,
36→			keys: { p256dh: keys.p256dh, auth: keys.auth }
37→		};
38→
39→		const existing = getPushSubscriptionByEndpoint(this.db, sub.endpoint);
40→		if (existing) {
41→			return jsonResponse({ ok: true }, 200);
42→		}
43→
44→		createPushSubscription(this.db, {
45→			id: generateId(),
46→			endpoint: sub.endpoint,
47→			p256dh: sub.keys.p256dh,
48→			auth: sub.keys.auth
49→		});
50→		await this.pushService.subscribe(sub);
51→		return jsonResponse({ ok: true }, 201);
52→	}
53→
54→	async handleUnsubscribe(endpoint: string): Promise<Response> {
55→		deletePushSubscription(this.db, endpoint);
56→		await this.pushService.unsubscribe(endpoint);
57→		return jsonResponse({ ok: true }, 200);
58→	}
59→}
