 1→import type { FeedEntry } from '$lib/types/feed.js';
 2→import type { PushService, PushNotificationPayload } from './push-service.js';
 3→
 4→/**
 5→ * Determine if a feed entry should trigger a push notification and return
 6→ * the payload if so, or null if the entry should be silent.
 7→ */
 8→export function buildNotificationPayload(
 9→	entry: FeedEntry,
10→	sessionId: string
11→): PushNotificationPayload | null {
12→	if (entry.role !== 'system') return null;
13→
14→	const phase = entry.metadata?.phase;
15→	const status = entry.metadata?.status;
16→	const content = entry.content;
17→
18→	// Human input needed
19→	if (
20→		content.toLowerCase().includes('input needed') ||
21→		content.toLowerCase().includes('waiting for')
22→	) {
23→		return {
24→			title: 'HALO — Input Needed',
25→			body: content,
26→			url: `/sessions/${sessionId}`,
27→			tag: `session-${sessionId}-input`
28→		};
29→	}
30→
31→	// Failure
32→	if (
33→		status === 'error' ||
34→		content.toLowerCase().includes('failed') ||
35→		content.toLowerCase().includes('error')
36→	) {
37→		return {
38→			title: 'HALO — Task Failed',
39→			body: content,
40→			url: `/sessions/${sessionId}`,
41→			tag: `session-${sessionId}-failure`
42→		};
43→	}
44→
45→	// Completion
46→	if (
47→		status === 'success' ||
48→		content.toLowerCase().includes('complete') ||
49→		content.toLowerCase().includes('done')
50→	) {
51→		return {
52→			title: 'HALO — Task Complete',
53→			body: content,
54→			url: `/sessions/${sessionId}`,
55→			tag: `session-${sessionId}-complete`
56→		};
57→	}
58→
59→	// Phase transition
60→	if (phase) {
61→		return {
62→			title: `HALO — ${phase}`,
63→			body: content,
64→			url: `/sessions/${sessionId}`,
65→			tag: `session-${sessionId}-phase`
66→		};
67→	}
68→
69→	return null;
70→}
71→
72→export async function notifyOnFeedEntry(pushService: PushService, entry: FeedEntry): Promise<void> {
73→	const payload = buildNotificationPayload(entry, entry.sessionId);
74→	if (!payload) return;
75→
76→	try {
77→		await pushService.broadcast(payload);
78→	} catch (err) {
79→		console.error('[push] Failed to broadcast notification:', err);
80→	}
81→}
