 1→import { subscribeAllFeedEntries } from '../sessions/feed-emitter.js';
 2→import { notifyOnFeedEntry } from './push-notifier.js';
 3→import type { PushService } from './push-service.js';
 4→
 5→let _unsubscribe: (() => void) | null = null;
 6→
 7→/**
 8→ * Start watching all feed entries and sending push notifications for
 9→ * notable events (phase transitions, failures, completions, input-needed).
10→ * Safe to call multiple times — only one watcher is registered.
11→ */
12→export function startPushWatcher(pushService: PushService): void {
13→	if (_unsubscribe) return;
14→
15→	_unsubscribe = subscribeAllFeedEntries((entry) => {
16→		notifyOnFeedEntry(pushService, entry).catch((err) => {
17→			console.error('[push] Watcher error:', err);
18→		});
19→	});
20→}
21→
22→export function stopPushWatcher(): void {
23→	_unsubscribe?.();
24→	_unsubscribe = null;
25→}
