 1→import { WebPushService, generateVapidKeys } from './web-push-service.js';
 2→import { getDb } from '../db/index.js';
 3→
 4→interface PushSingleton {
 5→	service: WebPushService;
 6→	vapidPublicKey: string;
 7→}
 8→
 9→let _singleton: PushSingleton | null = null;
10→
11→function createSingleton(): PushSingleton {
12→	const publicKey = process.env.VAPID_PUBLIC_KEY;
13→	const privateKey = process.env.VAPID_PRIVATE_KEY;
14→	const email = process.env.VAPID_EMAIL ?? 'admin@halo.local';
15→
16→	let vapidPublicKey: string;
17→	let vapidPrivateKey: string;
18→
19→	if (publicKey && privateKey) {
20→		vapidPublicKey = publicKey;
21→		vapidPrivateKey = privateKey;
22→	} else {
23→		// Generate ephemeral keys for development
24→		const keys = generateVapidKeys();
25→		vapidPublicKey = keys.publicKey;
26→		vapidPrivateKey = keys.privateKey;
27→		console.warn(
28→			'[push] No VAPID_PUBLIC_KEY/VAPID_PRIVATE_KEY env vars set. ' +
29→				'Generated ephemeral VAPID keys — push subscriptions will break on restart.'
30→		);
31→		console.warn('[push] Public key (set as VAPID_PUBLIC_KEY):', vapidPublicKey);
32→	}
33→
34→	const service = new WebPushService(getDb(), {
35→		publicKey: vapidPublicKey,
36→		privateKey: vapidPrivateKey,
37→		email
38→	});
39→
40→	return { service, vapidPublicKey };
41→}
42→
43→export function getPushSingleton(): PushSingleton {
44→	if (!_singleton) {
45→		_singleton = createSingleton();
46→	}
47→	return _singleton;
48→}
49→
50→export function getPushService(): WebPushService {
51→	return getPushSingleton().service;
52→}
53→
54→export function getVapidPublicKey(): string {
55→	return getPushSingleton().vapidPublicKey;
56→}
