 1→import type { RequestHandler } from '@sveltejs/kit';
 2→import { parseRequestBody, errorResponse } from '$lib/server/api-utils.js';
 3→import { PushController } from '$lib/server/push/push-controller.js';
 4→import { getPushService } from '$lib/server/push/singleton.js';
 5→import { getDb } from '$lib/server/db/index.js';
 6→
 7→function getController(): PushController {
 8→	return new PushController(getDb(), getPushService());
 9→}
10→
11→export const POST: RequestHandler = async ({ request }) => {
12→	try {
13→		const body = await parseRequestBody<unknown>(request);
14→		return await getController().handleSubscribe(body);
15→	} catch {
16→		return errorResponse('Invalid request body', 400);
17→	}
18→};
19→
20→export const DELETE: RequestHandler = async ({ request }) => {
21→	try {
22→		const body = await parseRequestBody<{ endpoint: string }>(request);
23→		if (!body.endpoint || typeof body.endpoint !== 'string') {
24→			return errorResponse('endpoint is required', 400);
25→		}
26→		return await getController().handleUnsubscribe(body.endpoint);
27→	} catch {
28→		return errorResponse('Invalid request body', 400);
29→	}
30→};
