1→import type { RequestHandler } from '@sveltejs/kit';
2→import { jsonResponse } from '$lib/server/api-utils.js';
3→import { getVapidPublicKey } from '$lib/server/push/singleton.js';
4→
5→export const GET: RequestHandler = () => {
6→	const publicKey = getVapidPublicKey();
7→	return jsonResponse({ publicKey });
8→};
