  1→import { writable } from 'svelte/store';
  2→
  3→export type PushPermission = 'default' | 'granted' | 'denied';
  4→
  5→export const pushPermission = writable<PushPermission>('default');
  6→export const pushSubscribed = writable<boolean>(false);
  7→
  8→/** URL-safe base64 decode for VAPID public key */
  9→function urlBase64ToUint8Array(base64String: string): ArrayBuffer {
 10→	const padding = '='.repeat((4 - (base64String.length % 4)) % 4);
 11→	const base64 = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
 12→	const rawData = atob(base64);
 13→	const uint8 = Uint8Array.from([...rawData].map((c) => c.charCodeAt(0)));
 14→	return uint8.buffer.slice(uint8.byteOffset, uint8.byteOffset + uint8.byteLength);
 15→}
 16→
 17→async function fetchVapidPublicKey(): Promise<string> {
 18→	const res = await fetch('/api/push/vapid-public-key');
 19→	if (!res.ok) throw new Error('Failed to fetch VAPID public key');
 20→	const { publicKey } = (await res.json()) as { publicKey: string };
 21→	return publicKey;
 22→}
 23→
 24→export async function requestPushPermission(): Promise<PushPermission> {
 25→	if (!('Notification' in window) || !('serviceWorker' in navigator)) {
 26→		return 'denied';
 27→	}
 28→
 29→	const result = await Notification.requestPermission();
 30→	pushPermission.set(result as PushPermission);
 31→	return result as PushPermission;
 32→}
 33→
 34→export async function subscribeToPush(): Promise<boolean> {
 35→	if (!('serviceWorker' in navigator) || !('PushManager' in window)) {
 36→		return false;
 37→	}
 38→
 39→	try {
 40→		const vapidPublicKey = await fetchVapidPublicKey();
 41→		const registration = await navigator.serviceWorker.ready;
 42→
 43→		const existing = await registration.pushManager.getSubscription();
 44→		if (existing) {
 45→			await sendSubscriptionToServer(existing);
 46→			pushSubscribed.set(true);
 47→			return true;
 48→		}
 49→
 50→		const subscription = await registration.pushManager.subscribe({
 51→			userVisibleOnly: true,
 52→			applicationServerKey: urlBase64ToUint8Array(vapidPublicKey)
 53→		});
 54→
 55→		await sendSubscriptionToServer(subscription);
 56→		pushSubscribed.set(true);
 57→		return true;
 58→	} catch (err) {
 59→		console.error('[push] Failed to subscribe:', err);
 60→		return false;
 61→	}
 62→}
 63→
 64→async function sendSubscriptionToServer(subscription: PushSubscription): Promise<void> {
 65→	const json = subscription.toJSON();
 66→	await fetch('/api/push/subscribe', {
 67→		method: 'POST',
 68→		headers: { 'content-type': 'application/json' },
 69→		body: JSON.stringify({
 70→			endpoint: subscription.endpoint,
 71→			keys: {
 72→				p256dh: json.keys?.p256dh ?? '',
 73→				auth: json.keys?.auth ?? ''
 74→			}
 75→		})
 76→	});
 77→}
 78→
 79→export async function unsubscribeFromPush(): Promise<void> {
 80→	if (!('serviceWorker' in navigator)) return;
 81→
 82→	try {
 83→		const registration = await navigator.serviceWorker.ready;
 84→		const subscription = await registration.pushManager.getSubscription();
 85→		if (subscription) {
 86→			await fetch('/api/push/subscribe', {
 87→				method: 'DELETE',
 88→				headers: { 'content-type': 'application/json' },
 89→				body: JSON.stringify({ endpoint: subscription.endpoint })
 90→			});
 91→			await subscription.unsubscribe();
 92→		}
 93→		pushSubscribed.set(false);
 94→	} catch (err) {
 95→		console.error('[push] Failed to unsubscribe:', err);
 96→	}
 97→}
 98→
 99→export function initPushState(): void {
100→	if (!('Notification' in window)) return;
101→	pushPermission.set(Notification.permission as PushPermission);
102→}
