 6→describe('runMigrations', () => {
 7→	let db: Database.Database;
 8→
 9→	beforeEach(() => {
10→		db = new Database(':memory:');
11→	});
12→
13→	it('creates the _migrations tracking table', () => {
14→		runMigrations(db);
15→		const row = db
16→			.prepare("SELECT name FROM sqlite_master WHERE type='table' AND name='_migrations'")
17→			.get();
18→		expect(row).toBeDefined();
19→	});
20→
21→	it('applies the initial schema migration', () => {
22→		runMigrations(db);
23→		const tables = db
24→			.prepare(
25→				"SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE '\\_\\_%' ESCAPE '\\' ORDER BY name"
26→			)
27→			.all() as { name: string }[];
28→		const names = tables.map((t) => t.name);
29→		expect(names).toContain('containers');
30→		expect(names).toContain('sessions');
31→		expect(names).toContain('feed_entries');
32→	});
33→
34→	it('tracks applied migrations', () => {
35→		runMigrations(db);
36→		const rows = db.prepare('SELECT filename FROM _migrations ORDER BY filename').all() as {
37→			filename: string;
38→		}[];
39→		expect(rows.length).toBeGreaterThan(0);
40→		expect(rows[0].filename).toBe('001-initial-schema.sql');
41→	});
42→
43→	it('is idempotent — running twice does not throw or duplicate', () => {
44→		runMigrations(db);
45→		const rowsBefore = db.prepare('SELECT filename FROM _migrations').all();
46→		expect(() => runMigrations(db)).not.toThrow();
47→		const rowsAfter = db.prepare('SELECT filename FROM _migrations').all();
48→		expect(rowsAfter.length).toBe(rowsBefore.length);
49→	});
50→});
