  1→// HALO Service Worker — App Shell Cache
  2→const CACHE_NAME = 'halo-shell-v1';
  3→
  4→// App shell resources to cache on install
  5→const SHELL_URLS = ['/'];
  6→
  7→self.addEventListener('install', (event) => {
  8→	event.waitUntil(
  9→		caches.open(CACHE_NAME).then((cache) => {
 10→			return cache.addAll(SHELL_URLS);
 11→		})
 12→	);
 13→	// Activate new service worker immediately without waiting
 14→	self.skipWaiting();
 15→});
 16→
 17→self.addEventListener('activate', (event) => {
 18→	// Remove old caches
 19→	event.waitUntil(
 20→		caches.keys().then((keys) => {
 21→			return Promise.all(keys.filter((key) => key !== CACHE_NAME).map((key) => caches.delete(key)));
 22→		})
 23→	);
 24→	// Take control of all clients immediately
 25→	self.clients.claim();
 26→});
 27→
 28→self.addEventListener('fetch', (event) => {
 29→	const { request } = event;
 30→	const url = new URL(request.url);
 31→
 32→	// Only handle same-origin requests
 33→	if (url.origin !== self.location.origin) return;
 34→
 35→	// Skip API routes, SSE streams, and WebSocket upgrades — always network
 36→	if (
 37→		url.pathname.startsWith('/api/') ||
 38→		url.pathname.startsWith('/ide/') ||
 39→		url.pathname.startsWith('/port/')
 40→	) {
 41→		return;
 42→	}
 43→
 44→	// For navigation requests (HTML pages): network-first, fall back to cached shell
 45→	if (request.mode === 'navigate') {
 46→		event.respondWith(
 47→			fetch(request)
 48→				.then((response) => {
 49→					// Cache successful navigation responses
 50→					if (response.ok) {
 51→						const clone = response.clone();
 52→						caches.open(CACHE_NAME).then((cache) => cache.put(request, clone));
 53→					}
 54→					return response;
 55→				})
 56→				.catch(() => {
 57→					// Offline: return cached shell
 58→					return caches.match('/') ?? Response.error();
 59→				})
 60→		);
 61→		return;
 62→	}
 63→
 64→	// For static assets: cache-first
 65→	event.respondWith(
 66→		caches.match(request).then((cached) => {
 67→			if (cached) return cached;
 68→
 69→			return fetch(request).then((response) => {
 70→				if (response.ok) {
 71→					const clone = response.clone();
 72→					caches.open(CACHE_NAME).then((cache) => cache.put(request, clone));
 73→				}
 74→				return response;
 75→			});
 76→		})
 77→	);
 78→});
