 94→	const title = payload.title ?? 'HALO';
 95→	const options = {
 96→		body: payload.body ?? '',
 97→		icon: '/icons/icon-192.png',
 98→		badge: '/icons/icon-192.png',
 99→		tag: payload.tag ?? 'halo-notification',
100→		data: { url: payload.url ?? '/' },
101→		requireInteraction: false
102→	};
