107→self.addEventListener('notificationclick', (event) => {
108→	event.notification.close();
109→
110→	const url = event.notification.data?.url ?? '/';
111→
112→	event.waitUntil(
113→		self.clients.matchAll({ type: 'window', includeUncontrolled: true }).then((clients) => {
114→			// Focus existing window if one is open
115→			for (const client of clients) {
116→				if (client.url.includes(self.location.origin) && 'focus' in client) {
117→					client.navigate(url);
118→					return client.focus();
119→				}
120→			}
121→			// Otherwise open a new window
122→			if (self.clients.openWindow) {
123→				return self.clients.openWindow(url);
124→			}
125→		})
126→	);
