 17→// ---------------------------------------------------------------------------
 18→// Hop-by-hop headers must not be forwarded to/from the upstream
 19→// ---------------------------------------------------------------------------
 20→
 21→const HOP_BY_HOP = new Set([
 22→	'connection',
 23→	'keep-alive',
 24→	'proxy-authenticate',
 25→	'proxy-authorization',
 26→	'te',
 27→	'trailers',
 28→	'transfer-encoding',
 29→	'upgrade'
 30→]);
