 32→// ---------------------------------------------------------------------------
 33→// Helper: build the set of running container names from the DB
 34→// ---------------------------------------------------------------------------
 35→
 36→function getRunningContainerNames(): Set<string> {
 37→	const db = getDb();
 38→	const rows = getAllContainers(db);
 39→	return new Set(rows.filter((r) => r.status === 'running').map((r) => r.name));
