 42→// ---------------------------------------------------------------------------
 43→// SvelteKit handle hook — intercepts HTTP proxy requests
 44→// ---------------------------------------------------------------------------
 45→
 46→export const handle: Handle = async ({ event, resolve }) => {
 47→	const { pathname, search } = event.url;
 48→
 49→	if (!pathname.startsWith('/ide/') && !pathname.startsWith('/port/')) {
 50→		return resolve(event);
 51→	}
 52→
 53→	const runningContainers = getRunningContainerNames();
 54→	const parsed = parseProxyPath(pathname, runningContainers);
 55→
 56→	if (!parsed) {
 57→		return new Response(JSON.stringify({ error: 'Container not found or not running' }), {
 58→			status: 404,
 59→			headers: { 'content-type': 'application/json' }
 60→		});
 61→	}
 62→
 63→	const { target, targetPath } = parsed;
 64→	// Append query string to the proxied path
 65→	const fullTargetPath = targetPath + search;
 66→
 67→	// Build forwarded request headers (strip hop-by-hop)
 68→	const requestHeaders: Record<string, string | string[]> = {};
 69→	event.request.headers.forEach((value, key) => {
 70→		if (!HOP_BY_HOP.has(key.toLowerCase())) {
 71→			requestHeaders[key] = value;
 72→		}
 73→	});
 74→	requestHeaders['x-forwarded-for'] = event.getClientAddress();
 75→	requestHeaders['x-forwarded-proto'] = event.url.protocol.replace(':', '');
 76→
 77→	// Read body for non-GET/HEAD methods
 78→	const body =
 79→		event.request.method !== 'GET' && event.request.method !== 'HEAD'
 80→			? Buffer.from(await event.request.arrayBuffer())
 81→			: null;
 82→
 83→	let proxyResp;
 84→	try {
 85→		proxyResp = await forwardRequest(target, fullTargetPath, {
 86→			method: event.request.method,
 87→			headers: requestHeaders,
 88→			body
 89→		});
 90→	} catch {
 91→		return new Response(JSON.stringify({ error: 'Bad Gateway' }), {
 92→			status: 502,
 93→			headers: { 'content-type': 'application/json' }
 94→		});
 95→	}
 96→
 97→	// Build response headers (strip hop-by-hop)
 98→	const responseHeaders = new Headers();
 99→	for (const [key, value] of Object.entries(proxyResp.headers)) {
100→		if (HOP_BY_HOP.has(key.toLowerCase())) continue;
101→		if (Array.isArray(value)) {
102→			for (const v of value) responseHeaders.append(key, v);
103→		} else if (value !== undefined) {
104→			responseHeaders.set(key, value);
105→		}
106→	}
107→
108→	return new Response(new Uint8Array(proxyResp.body), {
109→		status: proxyResp.status,
110→		headers: responseHeaders
111→	});
112→};
