114→// ---------------------------------------------------------------------------
115→// WebSocket upgrade proxy — wire this into the Node.js HTTP server's
116→// 'upgrade' event alongside the terminal ws-handler.
117→// ---------------------------------------------------------------------------
118→
119→/**
120→ * Handle HTTP upgrade requests for proxy paths.
121→ *
122→ * URL patterns handled:
123→ *   /ide/<container>[/<path>]   → <container>:8443
124→ *   /port/<container>/<port>[/<path>] → <container>:<port>
125→ *
126→ * Call this from the server's `upgrade` event before delegating to the
127→ * terminal WebSocket handler.
128→ */
129→export function handleProxyUpgrade(req: IncomingMessage, socket: Duplex, head: Buffer): boolean {
130→	const pathname = req.url ?? '';
131→
132→	if (!pathname.startsWith('/ide/') && !pathname.startsWith('/port/')) {
133→		return false;
134→	}
135→
136→	const runningContainers = getRunningContainerNames();
137→	const parsed = parseProxyPath(pathname, runningContainers);
138→
139→	if (!parsed) {
140→		socket.write('HTTP/1.1 404 Not Found\r\nConnection: close\r\n\r\n');
141→		socket.destroy();
142→		return true;
143→	}
144→
145→	const { target, targetPath } = parsed;
146→	proxyWebSocketUpgrade(target, targetPath, req, socket, head);
147→	return true;
148→}
